class Node:
    def __init__(self, data):
        self.data = data
        self.next = None

class SinglyLinkedList:
    def __init__(self):
        self.head = None

    def is_empty(self):
        return self.head is None

    def insert_at_beginning(self, data):
        new_node = Node(data)
        new_node.next = self.head
        self.head = new_node

    def insert_at_end(self, data):
        new_node = Node(data)
        if self.head is None:
            self.head = new_node
            return
        current = self.head
        while current.next:
            current = current.next
        current.next = new_node

    def delete_node(self, key):
        current = self.head
        if current and current.data == key:
            self.head = current.next
            return True
        while current:
            if current.next and current.next.data == key:
                current.next = current.next.next
                return True
            current = current.next
        return False

    def search(self, key):
        current = self.head
        position = 0
        while current:
            if current.data == key:
                return position
            current = current.next
            position += 1
        return -1

    def traverse(self):
        elements = []
        current = self.head
        while current:
            elements.append(str(current.data))
            current = current.next
        return " -> ".join(elements) + " -> NULL"

    def length(self):
        count = 0
        current = self.head
        while current:
            count += 1
            current = current.next
        return count

# Practical demonstration
if __name__ == "__main__":
    sll = SinglyLinkedList()

    # Insert elements
    sll.insert_at_end(10)
    sll.insert_at_end(20)
    sll.insert_at_end(30)
    sll.insert_at_beginning(5)

    print("Linked List:", sll.traverse())
    print("Length:", sll.length())
    print("Search 20 at index:", sll.search(20))

    sll.delete_node(20)
    print("After deleting 20:", sll.traverse())

class DNode:
    def __init__(self, data):
        self.data = data
        self.prev = None
        self.next = None

class DoublyLinkedList:
    def __init__(self):
        self.head = None
        self.tail = None

    def is_empty(self):
        return self.head is None

    def insert_at_front(self, data):
        new_node = DNode(data)
        if self.head is None:
            self.head = self.tail = new_node
        else:
            new_node.next = self.head
            self.head.prev = new_node
            self.head = new_node

    def insert_at_end(self, data):
        new_node = DNode(data)
        if self.tail is None:
            self.head = self.tail = new_node
        else:
            new_node.prev = self.tail
            self.tail.next = new_node
            self.tail = new_node

    def delete_node(self, node):
        if node.prev:
            node.prev.next = node.next
        else:
            self.head = node.next
        if node.next:
            node.next.prev = node.prev
        else:
            self.tail = node.prev

    def traverse_forward(self):
        result = []
        current = self.head
        while current:
            result.append(str(current.data))
            current = current.next
        return " <-> ".join(result)

    def traverse_backward(self):
        result = []
        current = self.tail
        while current:
            result.append(str(current.data))
            current = current.prev
        return " <-> ".join(result)

    def search(self, key):
        current = self.head
        while current:
            if current.data == key:
                return current
            current = current.next
        return None

# Practical demonstration
if __name__ == "__main__":
    dll = DoublyLinkedList()

    # Insert elements
    dll.insert_at_end(10)
    dll.insert_at_end(20)
    dll.insert_at_end(30)
    dll.insert_at_front(5)

    print("Forward traversal:", dll.traverse_forward())
    print("Backward traversal:", dll.traverse_backward())

    # Delete middle node
    node_to_delete = dll.search(20)
    if node_to_delete:
        dll.delete_node(node_to_delete)

    print("After deleting 20:", dll.traverse_forward())

class CNode:
    def __init__(self, task_name, burst_time):
        self.task_name = task_name
        self.burst_time = burst_time
        self.next = None

class CircularLinkedList:
    def __init__(self):
        self.head = None
        self.tail = None
        self.size = 0

    def is_empty(self):
        return self.size == 0

    def append(self, task_name, burst_time):
        new_node = CNode(task_name, burst_time)
        if self.head is None:
            self.head = self.tail = new_node
            new_node.next = self.head
        else:
            self.tail.next = new_node
            new_node.next = self.head
            self.tail = new_node
        self.size += 1

    def remove_task(self, task_name):
        if self.is_empty():
            return False
        current = self.head
        while True:
            if current.task_name == task_name:
                if current == self.head:
                    self.head = current.next
                    self.tail.next = self.head
                elif current == self.tail:
                    prev = self.head
                    while prev.next != self.tail:
                        prev = prev.next
                    prev.next = self.head
                    self.tail = prev
                else:
                    prev = self.head
                    while prev.next != current:
                        prev = prev.next
                    prev.next = current.next
                self.size -= 1
                return True
            current = current.next
            if current == self.head:
                break
        return False

    def round_robin_schedule(self, time_slice):
        if self.is_empty():
            return
        current = self.head
        completed = []

        print(f"\n=== Round Robin Scheduling (Time Slice: {time_slice}) ===")
        while self.size > 0:
            task = current.task_name
            remaining = current.burst_time

            if remaining <= time_slice:
                print(f"Executing {task} for {remaining} units -> COMPLETED")
                completed.append(task)
                self.remove_task(task)
                if self.is_empty():
                    break
                current = current.next if current != self.tail else self.head
            else:
                print(f"Executing {task} for {time_slice} units -> {remaining - time_slice} remaining")
                current.burst_time -= time_slice
                current = current.next

        return completed

# Practical demonstration
if __name__ == "__main__":
    scheduler = CircularLinkedList()

    # Add tasks with burst times
    scheduler.append("P1", 10)
    scheduler.append("P2", 5)
    scheduler.append("P3", 8)
    scheduler.append("P4", 3)

    print("Tasks in queue:")
    current = scheduler.head
    for _ in range(scheduler.size):
        print(f"  {current.task_name} (Burst: {current.burst_time})")
        current = current.next

    # Execute using Round Robin
    scheduler.round_robin_schedule(time_slice=4)
